// build-media-assets — Validate Inputs
// Validates upstream artifacts needed for media generation.

const input = $input.first().json;

const runtimeConfig   = input.runtime_config   || {};
const storeProfile    = input.store_profile     || null;
const brandPositioning = input.brand_positioning || null;
const storeBlueprint  = input.store_blueprint   || null;
const contentStrategy = input.content_strategy  || null;
const projectId       = input.project_id        || runtimeConfig.project_id || null;

if (!projectId) {
  throw new Error('MISSING_INPUT: build-media-assets requires project_id');
}
if (!storeProfile) {
  throw new Error('MISSING_ARTIFACT: store_profile is required for visual system derivation');
}
if (!brandPositioning) {
  throw new Error('MISSING_ARTIFACT: brand_positioning is required for visual system derivation');
}
if (!storeBlueprint) {
  throw new Error('MISSING_ARTIFACT: store_blueprint is required (products list)');
}

const products = storeBlueprint.products || [];
if (products.length === 0) {
  throw new Error('INVALID_BLUEPRINT: store_blueprint.products is empty — nothing to generate media for');
}

// Resolve media config
const allowMediaGeneration = runtimeConfig.allow_media_generation === true || runtimeConfig.allow_media_generation === 'true';
const mediaModel = runtimeConfig.media_generation_model || 'dall-e-3';
const mediaMode = allowMediaGeneration ? 'full_generation' : 'prompts_only';

return [{
  json: {
    project_id:         projectId,
    runtime_config:     runtimeConfig,
    store_profile:      storeProfile,
    brand_positioning:  brandPositioning,
    store_blueprint:    storeBlueprint,
    content_strategy:   contentStrategy,
    products:           products,
    allow_generation:   allowMediaGeneration,
    media_model:        mediaModel,
    media_mode:         mediaMode,
    cloud_mode:         runtimeConfig.cloud_mode || false,
  },
}];

// build-media-assets — Derive Visual System (Phase 9A)
// Deterministic art direction layer derived from brand_positioning + store_profile.
// NO randomness. Every derivation is a pure function of inputs.

const input = $input.first().json;
const bp = input.brand_positioning;
const sp = input.store_profile;

// ── Style derivation rules ────────────────────────────────────────────────
// Background: derived from price_positioning + brand_role
const backgroundMap = {
  'luxury':       'soft-gradient',
  'premium':      'soft-gradient',
  'mass-premium': 'neutral-studio',
  'mass-market':  'clean-white',
  'budget':       'clean-white',
};
const background = backgroundMap[sp.price_positioning] || 'clean-white';

// Lighting: derived from tone_of_voice
const lightingMap = {
  'clear-direct':          'flat-even',
  'premium-confident':     'dramatic-directional',
  'warm-helpful':          'warm-golden',
  'editorial-smart':       'natural-ambient',
  'playful-bold':          'natural-ambient',
  'technical-trustworthy': 'soft-studio',
};
const toneStyle = (bp.tone_of_voice && bp.tone_of_voice.style) || 'clear-direct';
const lighting = lightingMap[toneStyle] || 'soft-studio';

// Color logic: derived from brand_role + price_positioning
const colorMap = {
  'specialist':        'neutral-dominant',
  'curator':           'warm-accent',
  'problem-solver':    'neutral-dominant',
  'premium-innovator': 'cool-accent',
  'editorial-guide':   'warm-accent',
  'value-leader':      'brand-primary',
};
const colorLogic = colorMap[bp.brand_role] || 'neutral-dominant';

// Contrast: derived from price_positioning
const contrastMap = {
  'luxury':       'soft-editorial',
  'premium':      'balanced-natural',
  'mass-premium': 'high-clarity',
  'mass-market':  'punchy-commercial',
  'budget':       'punchy-commercial',
};
const contrastProfile = contrastMap[sp.price_positioning] || 'high-clarity';

// ── Composition derivation ────────────────────────────────────────────────
const framingMap = {
  'specialist':        'centered-subject',
  'curator':           'rule-of-thirds',
  'premium-innovator': 'asymmetric-editorial',
  'editorial-guide':   'rule-of-thirds',
  'value-leader':      'centered-subject',
  'problem-solver':    'centered-subject',
};
const framing = framingMap[bp.brand_role] || 'centered-subject';

const spacingMap = {
  'luxury':       'generous-breathing-room',
  'premium':      'generous-breathing-room',
  'mass-premium': 'balanced-margins',
  'mass-market':  'tight-product-focus',
  'budget':       'tight-product-focus',
};
const spacing = spacingMap[sp.price_positioning] || 'balanced-margins';

// Aspect ratios by vertical
const aspectRatios = ['1:1', '4:5', '16:9'];

// ── Product representation ────────────────────────────────────────────────
const shadowMap = {
  'luxury':       'reflection',
  'premium':      'soft-drop',
  'mass-premium': 'soft-drop',
  'mass-market':  'contact-shadow',
  'budget':       'none',
};
const shadowStyle = shadowMap[sp.price_positioning] || 'soft-drop';
const reflection = sp.price_positioning === 'luxury' || sp.price_positioning === 'premium';

const surfaceMap = {
  'luxury':       'glossy-surface',
  'premium':      'matte-white',
  'mass-premium': 'matte-white',
  'mass-market':  'none',
  'budget':       'none',
};
const surfaceMaterial = surfaceMap[sp.price_positioning] || 'none';

// ── Mood derivation ───────────────────────────────────────────────────────
const moodParts = [];
if (bp.brand_traits && bp.brand_traits.length > 0) {
  moodParts.push(...bp.brand_traits.slice(0, 3));
} else {
  moodParts.push('professional', 'clean');
}
const mood = moodParts.join(', ');

// ── Assemble visual system ────────────────────────────────────────────────
const visualSystem = {
  style: {
    background,
    lighting,
    color_logic: colorLogic,
    contrast_profile: contrastProfile,
    mood,
  },
  composition: {
    framing,
    spacing,
    aspect_ratios: aspectRatios,
  },
  product_representation: {
    isolation: true,
    shadow_style: shadowStyle,
    reflection,
    surface_material: surfaceMaterial,
  },
  consistency_rules: {
    no_random_backgrounds: true,
    no_random_camera_angles: true,
    no_mixed_lighting: true,
    color_temperature_locked: true,
    brand_watermark: false,
  },
  derived_from: {
    brand_role: bp.brand_role,
    tone_of_voice: toneStyle,
    price_positioning: sp.price_positioning,
    vertical: sp.vertical,
    visual_positioning_hint: bp.visual_positioning_hint || null,
    media_style_hint: bp.media_style_hint || null,
  },
};

return [{
  json: {
    ...input,
    visual_system: visualSystem,
  },
}];

// build-media-assets — Build Shot Plan + Generate Prompts (Phase 9B + 9C)
// Deterministic shot taxonomy + prompt template system.
// Every product gets the same fixed shot set.
// Every prompt is a pure function of (product, shot_type, visual_system).

const input = $input.first().json;
const vs = input.visual_system;
const products = input.products;
const bp = input.brand_positioning;
const projectId = input.project_id;
const mediaMode = input.media_mode;
const cloudMode = input.cloud_mode;

// ── Shot Taxonomy (Phase 9B) ──────────────────────────────────────────────
// Fixed set of shot types. Same for every product. No randomness.
const shotTaxonomy = {
  shot_types: [
    {
      shot_id: 'studio_packshot',
      shot_name: 'Studio Packshot',
      camera_angle: 'front-center',
      composition: 'centered-subject',
      background_type: 'pure-white',
      purpose: 'conversion',
      aspect_ratio: '1:1',
      priority: 1,
      required: true,
      prompt_emphasis: 'clean product isolation, sharp focus, ecommerce-ready',
    },
    {
      shot_id: 'clean_feature',
      shot_name: 'Clean Feature Shot',
      camera_angle: 'three-quarter-left',
      composition: 'rule-of-thirds-left',
      background_type: 'studio-gradient',
      purpose: 'clarity',
      aspect_ratio: '4:5',
      priority: 2,
      required: true,
      prompt_emphasis: 'key features visible, dimensional depth, detail clarity',
    },
    {
      shot_id: 'lifestyle_context',
      shot_name: 'Lifestyle Context',
      camera_angle: 'eye-level',
      composition: 'rule-of-thirds-right',
      background_type: 'contextual-environment',
      purpose: 'aspiration',
      aspect_ratio: '4:5',
      priority: 3,
      required: true,
      prompt_emphasis: 'product in natural use context, aspirational setting',
    },
    {
      shot_id: 'hero_wide',
      shot_name: 'Hero Wide Banner',
      camera_angle: 'eye-level',
      composition: 'negative-space-right',
      background_type: 'brand-color',
      purpose: 'hero-impact',
      aspect_ratio: '16:9',
      priority: 4,
      required: false,
      prompt_emphasis: 'dramatic presentation, banner-ready, space for text overlay',
    },
    {
      shot_id: 'detail_closeup',
      shot_name: 'Detail Closeup',
      camera_angle: 'macro-detail',
      composition: 'full-frame',
      background_type: 'surface-only',
      purpose: 'detail-verification',
      aspect_ratio: '1:1',
      priority: 5,
      required: false,
      prompt_emphasis: 'texture, material quality, craftsmanship details',
    },
  ],
};

// ── Prompt Template System (Phase 9C) ─────────────────────────────────────
// Pure function: (product, shot_type, visual_system) → deterministic prompt.
// No randomness. Structured phrasing. Stable across products.

function buildPrompt(product, shot, vs) {
  const parts = [];

  // Subject description
  const category = product.product_type || 'product';
  parts.push('Professional ecommerce product photograph of a ' + category + ': "' + product.title + '".');

  // Key features from description hint
  if (product.description_hint) {
    parts.push(product.description_hint + '.');
  }

  // Shot-specific composition
  const angleNames = {
    'front-center': 'straight-on front view',
    'three-quarter-left': 'three-quarter angle from the left',
    'three-quarter-right': 'three-quarter angle from the right',
    'top-down': 'top-down flat lay',
    'eye-level': 'eye-level perspective',
    'low-angle': 'low-angle hero perspective',
    '45-degree-above': '45 degree angle from above',
    'macro-detail': 'macro close-up detail shot',
  };
  parts.push('Camera angle: ' + (angleNames[shot.camera_angle] || shot.camera_angle) + '.');

  // Composition
  const compNames = {
    'centered-subject': 'Subject centered in frame',
    'rule-of-thirds-left': 'Subject positioned on left third',
    'rule-of-thirds-right': 'Subject positioned on right third',
    'full-frame': 'Subject fills the entire frame',
    'negative-space-right': 'Subject left with negative space on right for text',
    'negative-space-left': 'Subject right with negative space on left',
    'symmetrical': 'Symmetrical balanced composition',
  };
  parts.push((compNames[shot.composition] || shot.composition) + '.');

  // Background from visual system + shot override
  const bgNames = {
    'pure-white': 'Pure white seamless background',
    'studio-gradient': 'Subtle studio gradient background',
    'contextual-environment': 'Minimal, clean contextual environment appropriate for ' + category,
    'brand-color': 'Solid brand-aligned neutral background',
    'surface-only': 'Product on ' + (vs.product_representation.surface_material || 'clean surface'),
    'transparent': 'Clean background for transparency',
  };
  parts.push((bgNames[shot.background_type] || 'Clean background') + '.');

  // Lighting from visual system
  const lightNames = {
    'soft-studio': 'Soft, diffused studio lighting with gentle shadows',
    'dramatic-directional': 'Dramatic directional key light with defined shadows',
    'natural-ambient': 'Natural ambient daylight',
    'flat-even': 'Flat, even lighting with minimal shadows',
    'warm-golden': 'Warm golden-hour inspired lighting',
  };
  parts.push((lightNames[vs.style.lighting] || 'Professional studio lighting') + '.');

  // Shadow and reflection
  if (shot.background_type === 'pure-white' || shot.background_type === 'studio-gradient') {
    const shadowNames = {
      'soft-drop': 'Soft drop shadow beneath product',
      'contact-shadow': 'Subtle contact shadow only',
      'reflection': 'Glossy surface reflection beneath product',
      'none': 'No shadow',
      'ambient-occlusion': 'Natural ambient occlusion shadow',
    };
    parts.push((shadowNames[vs.product_representation.shadow_style] || '') + '.');
  }

  // Shot emphasis
  if (shot.prompt_emphasis) {
    parts.push(shot.prompt_emphasis + '.');
  }

  // Visual system mood
  if (vs.style.mood) {
    parts.push('Overall mood: ' + vs.style.mood + '.');
  }

  // Technical requirements
  parts.push('High resolution, sharp focus, professionally color-graded.');
  parts.push('Aspect ratio: ' + shot.aspect_ratio + '.');
  parts.push('Style: commercial product photography, ecommerce-optimized.');

  return parts.filter(p => p && p.trim()).join(' ');
}

// ── Build shot plan for all products ──────────────────────────────────────
const mediaAssets = [];
const requiredShots = shotTaxonomy.shot_types.filter(s => s.required);
const allShots = shotTaxonomy.shot_types;
const timestamp = new Date().toISOString();

// Determine storage base path
const basePath = cloudMode ? null : ('/assets/media/' + projectId);

for (const product of products) {
  const handle = product.handle || product.title.toLowerCase().replace(/[^a-z0-9]+/g, '-');

  for (const shot of allShots) {
    const assetId = handle + '-' + shot.shot_id;
    const prompt = buildPrompt(product, shot, vs);

    // Deterministic local path
    const shotFolder = shot.shot_id.replace(/_/g, '-');
    const localPath = basePath ? (basePath + '/' + handle + '/' + shotFolder + '/' + assetId + '.png') : null;

    // Shopify mapping (Phase 9G)
    let shopifyMapping = null;
    if (shot.shot_id === 'studio_packshot') {
      shopifyMapping = { target_type: 'product_image', target_handle: handle, position: 1 };
    } else if (shot.shot_id === 'clean_feature') {
      shopifyMapping = { target_type: 'product_image', target_handle: handle, position: 2 };
    } else if (shot.shot_id === 'lifestyle_context') {
      shopifyMapping = { target_type: 'product_image', target_handle: handle, position: 3 };
    } else if (shot.shot_id === 'hero_wide') {
      shopifyMapping = { target_type: 'collection_image', target_handle: (product.collections && product.collections[0]) || handle, position: null };
    }

    // Aspect ratio → pixel dimensions for DALL-E
    const dimMap = {
      '1:1':  '1024x1024',
      '4:5':  '1024x1280',
      '3:4':  '768x1024',
      '16:9': '1792x1024',
      '9:16': '1024x1792',
      '3:2':  '1536x1024',
      '2:3':  '1024x1536',
    };

    mediaAssets.push({
      asset_id: assetId,
      product_handle: handle,
      product_title: product.title,
      shot_type: shot.shot_id,
      prompt: prompt,
      status: 'prompt_only',
      local_path: localPath,
      url: null,
      metadata: {
        aspect_ratio: shot.aspect_ratio,
        generation_model: input.media_model,
        timestamp: timestamp,
        dimensions_px: dimMap[shot.aspect_ratio] || '1024x1024',
        file_size_bytes: null,
        quality_score: null,
      },
      shopify_mapping: shopifyMapping,
    });
  }
}

// ── Summary ───────────────────────────────────────────────────────────────
const summary = {
  products_processed: products.length,
  total_shots_planned: mediaAssets.length,
  prompts_generated: mediaAssets.length,
  images_generated: 0,
  images_failed: 0,
  images_skipped: 0,
  mode: mediaMode,
};

return [{
  json: {
    ...input,
    visual_system: vs,
    shot_taxonomy: shotTaxonomy,
    media_assets: mediaAssets,
    generation_summary: summary,
    storage: {
      mode: cloudMode ? 'cloud_inline' : 'local',
      base_path: basePath,
      total_files: 0,
      total_size_bytes: null,
    },
  },
}];

// build-media-assets — Image Generation Dispatcher
// Splits media_assets into individual items for the image generation node.
// Only processes required shots to manage API costs.

const input = $input.first().json;
const assets = input.media_assets;
const requiredOnly = assets.filter(a => {
  // Only generate required shots (priority <= 3)
  const taxonomy = input.shot_taxonomy.shot_types.find(s => s.shot_id === a.shot_type);
  return taxonomy && taxonomy.required;
});

// Pass metadata for reassembly
const items = requiredOnly.map((asset, idx) => ({
  json: {
    _asset_index: idx,
    _total_assets: requiredOnly.length,
    _project_id: input.project_id,
    asset_id: asset.asset_id,
    prompt: asset.prompt,
    dimensions: asset.metadata.dimensions_px,
    shot_type: asset.shot_type,
    product_handle: asset.product_handle,
    model: asset.metadata.generation_model,
  },
}));

return items;

// build-media-assets — Compile Media Manifest (Phase 9D + 9F + 9G)
// Assembles final output from generation results or prompt-only path.
// Includes quality gate stub and Shopify mapping.

const allItems = $input.all();
const firstItem = allItems[0].json;

// Detect which path we came from
const isGenerationPath = firstItem.hasOwnProperty('_asset_index') || (firstItem.body && firstItem.statusCode);
const isPromptOnlyPath = firstItem.hasOwnProperty('media_assets');

let result;

if (isPromptOnlyPath) {
  // ── Prompt-only path (no generation) ───────────────────────────────────
  const input = firstItem;
  result = {
    status: 'PHASE_9_PROMPTS_ONLY',
    project_id: input.project_id,
    completed_at: new Date().toISOString(),
    visual_system: input.visual_system,
    shot_taxonomy: input.shot_taxonomy,
    media_assets: input.media_assets,
    generation_summary: input.generation_summary,
    storage: input.storage,
    errors: [],
    warnings: ['PROMPTS_ONLY: allow_media_generation not set. Prompts generated but no images produced. Set runtime_config.allow_media_generation: true to generate.'],
  };
} else {
  // ── Generation path — reassemble results ─────────────────────────────
  const planItems = $('Build Shot Plan and Prompts').first().json;
  const mediaAssets = [...planItems.media_assets];
  let imagesGenerated = 0;
  let imagesFailed = 0;
  const errors = [];

  for (let i = 0; i < allItems.length; i++) {
    const resp = allItems[i].json;
    const dispatchItems = $('Prepare Generation Batch').all();
    const dispatch = dispatchItems[i]?.json || {};
    const assetId = dispatch.asset_id;

    // Find matching asset in manifest
    const assetIdx = mediaAssets.findIndex(a => a.asset_id === assetId);
    if (assetIdx === -1) continue;

    const statusCode = resp.statusCode || 0;
    const body = resp.body || resp;

    if (statusCode >= 200 && statusCode < 300 && body.data && body.data[0]) {
      // Success — update asset with URL
      mediaAssets[assetIdx].status = 'generated';
      mediaAssets[assetIdx].url = body.data[0].url || null;
      mediaAssets[assetIdx].metadata.timestamp = new Date().toISOString();
      imagesGenerated++;
    } else {
      // Failed
      mediaAssets[assetIdx].status = 'failed';
      const errMsg = body.error?.message || body.body?.error?.message || 'HTTP ' + statusCode;
      errors.push({ asset_id: assetId, error_type: 'generation_failed', message: errMsg });
      imagesFailed++;
    }
  }

  // Mark non-required shots that weren't sent for generation as skipped
  const imagesSkipped = mediaAssets.filter(a => a.status === 'prompt_only').length;

  // Quality gate stub (Phase 9F)
  // For now: all generated images pass. Future: implement actual validation.
  for (const asset of mediaAssets) {
    if (asset.status === 'generated') {
      asset.metadata.quality_score = 1.0; // Placeholder — replace with real scoring
    }
  }

  const totalGenerated = imagesGenerated;
  let status;
  if (imagesFailed === 0 && imagesGenerated > 0) {
    status = 'PHASE_9_COMPLETE';
  } else if (imagesGenerated > 0) {
    status = 'PHASE_9_PARTIAL';
  } else {
    status = 'PHASE_9_FAILED';
  }

  result = {
    status: status,
    project_id: planItems.project_id,
    completed_at: new Date().toISOString(),
    visual_system: planItems.visual_system,
    shot_taxonomy: planItems.shot_taxonomy,
    media_assets: mediaAssets,
    generation_summary: {
      products_processed: planItems.generation_summary.products_processed,
      total_shots_planned: mediaAssets.length,
      prompts_generated: mediaAssets.length,
      images_generated: imagesGenerated,
      images_failed: imagesFailed,
      images_skipped: imagesSkipped,
      mode: 'full_generation',
    },
    storage: planItems.storage,
    errors: errors,
    warnings: [],
  };
}

return [{ json: result }];
